import{_ as n,o as t,c as r,ae as a}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"Ultimate Error Handling & Bug Registry Protocol","description":"The mandatory process for detecting, logging, and resolving errors across the OpenSIN A2A fleet.","frontmatter":{"title":"Ultimate Error Handling & Bug Registry Protocol","description":"The mandatory process for detecting, logging, and resolving errors across the OpenSIN A2A fleet."},"headers":[],"relativePath":"best-practices/error-handling.md","filePath":"best-practices/error-handling.md"}'),s={name:"best-practices/error-handling.md"};function i(o,e,l,d,h,u){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="ultimate-error-handling-bug-registry-protocol" tabindex="-1">Ultimate Error Handling &amp; Bug Registry Protocol <a class="header-anchor" href="#ultimate-error-handling-bug-registry-protocol" aria-label="Permalink to &quot;Ultimate Error Handling &amp; Bug Registry Protocol&quot;">​</a></h1><blockquote><p><strong>⚠️ WICHTIGER HINWEIS AN ALLE AGENTEN UND ENTWICKLER ⚠️</strong> Diese Seite enthält die absolut bindenden Regeln für das Fehler-Management. Fehler dürfen <strong>NIEMALS</strong> ignoriert, lokal verschwiegen oder mit Annahmen &quot;weggewischt&quot; werden.</p></blockquote><hr><h2 id="_1-immediate-bug-registry-issue-protocol-priority-4-0" tabindex="-1">1. Immediate Bug Registry &amp; Issue Protocol (Priority -4.0) <a class="header-anchor" href="#_1-immediate-bug-registry-issue-protocol-priority-4-0" aria-label="Permalink to &quot;1. Immediate Bug Registry &amp; Issue Protocol (Priority -4.0)&quot;">​</a></h2><h3 id="was-passiert-hier" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Jeder Agent, jeder Coder und jedes Sub-System <strong>MUSS</strong> jeden noch so kleinen Bug, jede Exception, jedes unerwartete Verhalten (wie z.B. einen unerwarteten DOM-Status in <code>nodriver</code>, einen 404 von einer API oder einen Absturz eines n8n-Workflows) <strong>SOFORT</strong> als GitHub Issue im betroffenen Repository dokumentieren.</p><h3 id="warum-wird-es-so-gemacht" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Das GitHub Issue-System dient als unsere <strong>globale Bug-Bibliothek und Wissensdatenbank</strong>. Ein Problem, das ein Agent heute löst, wird morgen von einem anderen Agenten auf einem anderen Node ebenfalls angetroffen. Wenn der Bug nicht zentral mit Root-Cause und Fix verzeichnet ist, beginnt die Diagnose für jeden Agenten wieder bei Null.</p><h3 id="weshalb-nicht-anders" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Die Alternative (&quot;Ich repariere das schnell lokal, das muss ja keiner wissen&quot;) führt zu einem fragilen System, in dem Code-Änderungen an Modulen durchgeführt werden, ohne dass die Historie oder der Grund der Änderung nachvollziehbar sind. Zudem verhindert es, dass das <code>A2A-SIN-GitHub-Issues</code> Modul und <code>SIN-Hermes</code> ihre Dispatches und Self-Healing-Routinen aktivieren können.</p><h3 id="womit-hangt-es-zusammen" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><ul><li><strong>GitHub Issues</strong>: Das Issue MUSS das Label <code>Bug</code> oder einen entsprechenden Tag erhalten.</li><li><strong>GitLab LogCenter</strong>: Alle zugehörigen Logs, Screenshots (<code>/tmp/mXX_stepname_RESULT.png</code>) und Videos müssen via <code>gitlab_logcenter.py</code> hochgeladen werden, bevor das Issue erstellt wird. Das Issue enthält dann nur noch die Links zu den Artefakten.</li></ul><h3 id="was-sind-die-konsequenzen-bei-missachtung" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><ul><li><strong>Für das System:</strong> Wiederkehrende Fehler, da Agenten nicht aus vergangenen Fixes lernen können (kein durchsuchbares Issue-Gedächtnis).</li><li><strong>Für den Entwickler/Agenten:</strong> Sofortiger Entzug der Berechtigungen. Die Regel lautet: <strong>Zuerst Issue erstellen (oder bestehendes aktualisieren), DANN fixen.</strong></li></ul><hr><h2 id="_2-das-absolute-annahmen-verbot-priority-5-0" tabindex="-1">2. Das Absolute Annahmen-Verbot (Priority -5.0) <a class="header-anchor" href="#_2-das-absolute-annahmen-verbot-priority-5-0" aria-label="Permalink to &quot;2. Das Absolute Annahmen-Verbot (Priority -5.0)&quot;">​</a></h2><h3 id="was-passiert-hier-1" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-1" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Ein Agent darf <strong>NIEMALS</strong> Schlussfolgerungen ziehen oder Diagnosen aufstellen, ohne diese vorher durch harte Fakten (Code-Ausführung, Logs, API-Responses, DOM-Checks) bewiesen zu haben.</p><h3 id="warum-wird-es-so-gemacht-1" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-1" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>&quot;Ich denke, die API ist down&quot; oder &quot;Wahrscheinlich ist das Token abgelaufen&quot; sind Halluzinationen. Wenn ein Agent auf Basis von Annahmen einen Fix programmiert, verschlimmbessert er den Code, fügt Workarounds ein, die das eigentliche Problem (z.B. einen simplen Syntax-Fehler wie ein doppeltes Escaping) nur maskieren, und baut &quot;Tech-Debt&quot; (technische Schulden) auf.</p><h3 id="weshalb-nicht-anders-1" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-1" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Gute Software-Entwicklung basiert auf Kausalität: Aktion A führt zu Ergebnis B. Jede Code-Änderung muss kausal auf einen belegten Fehler zurückzuführen sein.</p><h3 id="womit-hangt-es-zusammen-1" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-1" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><ul><li><strong>100% Test-Beweis Pflicht</strong>: Eine Behauptung muss durch einen erfolgreichen Test verifiziert werden.</li><li><strong>DevTools-First Mandate</strong>: Frontend-Fehler dürfen nur nach Prüfung der echten DevTools-Console (<code>document.querySelector</code>, <code>element.offsetParent !== null</code>) diagnostiziert werden.</li></ul><h3 id="was-sind-die-konsequenzen-bei-missachtung-1" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-1" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Ein Agent, der Annahmen macht statt Fakten zu prüfen, dreht sich in einer Endlos-Schleife (Looping), verbrennt Token-Guthaben und liefert keinen echten Fix. <strong>Jeder Agent, der Annahmen trifft, fliegt SOFORT und PERMANENT aus dem Netzwerk.</strong></p><hr><h2 id="_3-global-fleet-self-healing-protocol-der-automatisierte-heilungsprozess" tabindex="-1">3. Global Fleet Self-Healing Protocol (Der automatisierte Heilungsprozess) <a class="header-anchor" href="#_3-global-fleet-self-healing-protocol-der-automatisierte-heilungsprozess" aria-label="Permalink to &quot;3. Global Fleet Self-Healing Protocol (Der automatisierte Heilungsprozess)&quot;">​</a></h2><h3 id="was-passiert-hier-2" tabindex="-1">WAS passiert hier? <a class="header-anchor" href="#was-passiert-hier-2" aria-label="Permalink to &quot;WAS passiert hier?&quot;">​</a></h3><p>Wenn ein Agent feststellt, dass er einen Fehler nicht lösen kann (z.B. weil eine Capability fehlt, eine API restriktiert ist oder seine Host-VM crasht), übergibt er das Problem an die Flotte. Er erstellt ein Issue, lädt die Logs ins GitLab LogCenter und delegiert die Lösung an <code>A2A-SIN-GitHub-Issues</code> und <code>SIN-Hermes</code>.</p><h3 id="warum-wird-es-so-gemacht-2" tabindex="-1">WARUM wird es so gemacht? <a class="header-anchor" href="#warum-wird-es-so-gemacht-2" aria-label="Permalink to &quot;WARUM wird es so gemacht?&quot;">​</a></h3><p>Ein einzelner Agent hat oft nur begrenzte Ressourcen und lokalen Kontext. Die Flotte (das gesamte &quot;Team Coder&quot; auf den HF VMs) kann die Aufgabe durch parallele Recherche (Oracle, Explore, Librarian) und kollektive Code-Generierung viel schneller und stabiler lösen. Dies macht das OpenSIN-Ökosystem zu einer gigantischen, sich selbst heilenden Maschine.</p><h3 id="weshalb-nicht-anders-2" tabindex="-1">WESHALB nicht anders? <a class="header-anchor" href="#weshalb-nicht-anders-2" aria-label="Permalink to &quot;WESHALB nicht anders?&quot;">​</a></h3><p>Silo-Lösungen scheitern an Komplexität, API-Limits (wie Cloudflare 403) oder Host-Einschränkungen (wie fehlende Node.js Module auf einer bestimmten VM). Nur die Schwarm-Intelligenz sichert Resilienz.</p><h3 id="womit-hangt-es-zusammen-2" tabindex="-1">WOMIT hängt es zusammen? <a class="header-anchor" href="#womit-hangt-es-zusammen-2" aria-label="Permalink to &quot;WOMIT hängt es zusammen?&quot;">​</a></h3><ul><li><strong>sin-a2a-agent-forge</strong>: Wenn ein Tool fehlt, muss der Agent sofort den Skill aufrufen und einen neuen Agenten bauen. &quot;Was dir fehlt, fehlt der gesamten Flotte – also erschaffe es autonom!&quot;</li></ul><h3 id="was-sind-die-konsequenzen-bei-missachtung-2" tabindex="-1">WAS sind die KONSEQUENZEN bei Missachtung? <a class="header-anchor" href="#was-sind-die-konsequenzen-bei-missachtung-2" aria-label="Permalink to &quot;WAS sind die KONSEQUENZEN bei Missachtung?&quot;">​</a></h3><p>Ein Agent, der in seinem Silo bleibt und wiederholt fehlschlägt, lähmt den Workflow des Benutzers und sabotiert das Paradigma des autonomen SIN Solvers. Das System erwartet, dass Hindernisse entweder souverän umschifft (&quot;Hacker Bypass&quot;) oder an die Flotte delegiert werden.</p><hr><p><em>Letzte Aktualisierung:</em> 2026-04-10 <em>Status:</em> <strong>AKTIV &amp; BINDEND</strong><em>Verantwortlich:</em> sin-zeus</p>',40)])])}const m=n(s,[["render",i]]);export{c as __pageData,m as default};
